CREATE TABLE `bill_booking_detail` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `bill_booking_id` varchar(45) DEFAULT NULL,
  `product_code` varchar(45) DEFAULT NULL,
  `delivery_items` int(10) unsigned DEFAULT NULL,
  `book_items` double DEFAULT NULL,
  `unit_name` varchar(45) DEFAULT NULL,
  `item_price` double DEFAULT NULL,
  `discount` text DEFAULT NULL,
  `amount` double DEFAULT NULL,
  `commission` double DEFAULT NULL,
  `row_id` int(10) unsigned DEFAULT NULL,
  `product_name` varchar(255) DEFAULT NULL,
  `location` varchar(45) DEFAULT NULL,
  `users` varchar(255) CHARACTER SET utf8 COLLATE utf8_unicode_ci DEFAULT NULL,
  `transdate` datetime DEFAULT NULL,
  `row_order` varchar(45) DEFAULT NULL,
  `customer_id` varchar(45) DEFAULT NULL,
  `prd_cost` double DEFAULT NULL,
  `is_package` varchar(45) DEFAULT NULL,
  `prd_master_id` varchar(45) DEFAULT NULL,
  `finish` varchar(45) DEFAULT NULL,
  `user` varchar(245) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_bill_booking_detail_bill_booking_id` (`bill_booking_id`),
  KEY `idx_bill_booking_detail_customer_id` (`customer_id`),
  KEY `idx_bill_booking_detail_prd_master_id` (`prd_master_id`),
  KEY `idx_bill_booking_detail_row_id` (`row_id`),
  KEY `idx_bill_booking_detail_transdate` (`transdate`)
) ENGINE=InnoDB AUTO_INCREMENT=321 DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci ROW_FORMAT=DYNAMIC;
