CREATE TABLE `bill_buy` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `billdate` date DEFAULT NULL,
  `order_id` varchar(45) DEFAULT NULL,
  `bill_buy_id` varchar(45) DEFAULT NULL,
  `seller_id` varchar(45) DEFAULT NULL,
  `seller_name` varchar(512) DEFAULT NULL,
  `seller_address` text DEFAULT NULL,
  `recivedate` date DEFAULT NULL,
  `reciveplace` text DEFAULT NULL,
  `reciverstatus` varchar(45) DEFAULT NULL,
  `user_realname` varchar(128) DEFAULT NULL,
  `user_name` varchar(128) DEFAULT NULL,
  `transdate` datetime DEFAULT NULL,
  `sum_total` double DEFAULT NULL,
  `discount` varchar(255) DEFAULT NULL,
  `balance` double DEFAULT NULL,
  `vat` double DEFAULT NULL,
  `paytype` int(10) unsigned DEFAULT NULL COMMENT '1 = cash 2 = credit',
  `note` text DEFAULT NULL,
  `cancel` varchar(45) DEFAULT NULL,
  `vat_status` varchar(45) CHARACTER SET utf8 COLLATE utf8_unicode_ci DEFAULT NULL,
  `location` varchar(45) DEFAULT NULL,
  `finalbalance` double DEFAULT NULL,
  `ref_doc` varchar(45) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `Index` (`paytype`) USING BTREE,
  KEY `Index2` (`bill_buy_id`) USING BTREE,
  KEY `Index3` (`billdate`) USING BTREE,
  KEY `Index4` (`recivedate`) USING BTREE,
  KEY `Index_6` (`cancel`),
  KEY `idx_bill_buy_order_id` (`order_id`),
  KEY `idx_bill_buy_seller_id` (`seller_id`),
  KEY `idx_bill_buy_transdate` (`transdate`)
) ENGINE=InnoDB AUTO_INCREMENT=191 DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci;
