/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `bill_salecash_detail` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `bill_salecash_id` varchar(45) CHARACTER SET latin1 COLLATE latin1_swedish_ci DEFAULT NULL,
  `product_code` varchar(45) CHARACTER SET latin1 COLLATE latin1_swedish_ci DEFAULT NULL,
  `delivery_items` int(10) unsigned DEFAULT NULL,
  `book_items` double DEFAULT NULL,
  `unit_name` varchar(45) DEFAULT NULL,
  `item_price` double DEFAULT NULL,
  `discount` text DEFAULT NULL,
  `amount` double DEFAULT NULL,
  `commission` double DEFAULT NULL,
  `row_id` int(10) unsigned DEFAULT NULL,
  `product_name` varchar(255) DEFAULT NULL,
  `location` varchar(45) CHARACTER SET latin1 COLLATE latin1_swedish_ci DEFAULT NULL,
  `users` varchar(255) CHARACTER SET utf8 COLLATE utf8_unicode_ci DEFAULT NULL,
  `transdate` datetime DEFAULT NULL,
  `row_order` varchar(45) DEFAULT NULL,
  `customer_id` varchar(45) DEFAULT NULL,
  `prd_cost` double DEFAULT NULL,
  `is_package` varchar(45) DEFAULT NULL,
  `master_prd_id` varchar(45) DEFAULT NULL,
  `saletype` varchar(45) DEFAULT NULL,
  `docid` varchar(45) DEFAULT NULL,
  `ref_doc` varchar(45) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_bill_salecash_detail_bill_salecash_id` (`bill_salecash_id`),
  KEY `idx_bill_salecash_detail_customer_id` (`customer_id`),
  KEY `idx_bill_salecash_detail_master_prd_id` (`master_prd_id`),
  KEY `idx_bill_salecash_detail_row_id` (`row_id`),
  KEY `idx_bill_salecash_detail_transdate` (`transdate`)
) ENGINE=InnoDB AUTO_INCREMENT=530 DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci ROW_FORMAT=DYNAMIC;
