/*!40000 ALTER TABLE `bill_salecash_detail` ENABLE KEYS */;
UNLOCK TABLES;
DROP TABLE IF EXISTS `bill_salecredit`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `bill_salecredit` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `billdate` date DEFAULT NULL,
  `quataion_id` varchar(45) CHARACTER SET latin1 COLLATE latin1_swedish_ci DEFAULT NULL,
  `bill_id` varchar(45) DEFAULT NULL,
  `cust_id` varchar(45) DEFAULT NULL,
  `cust_name` varchar(255) DEFAULT NULL,
  `cust_address` text DEFAULT NULL,
  `delivery_date` date DEFAULT NULL,
  `delivery_place` text DEFAULT NULL,
  `delivery_status` varchar(45) DEFAULT NULL,
  `staff_id` varchar(45) DEFAULT NULL,
  `staff_name` varchar(256) DEFAULT NULL,
  `staff_username` varchar(256) DEFAULT NULL,
  `commistion` double DEFAULT NULL,
  `transdate` datetime DEFAULT NULL,
  `note` text CHARACTER SET latin1 COLLATE latin1_swedish_ci DEFAULT NULL,
  `total` double DEFAULT NULL,
  `deposit` double DEFAULT NULL,
  `discount` varchar(45) DEFAULT NULL,
  `balance` double DEFAULT NULL,
  `vat` double DEFAULT NULL,
  `final_balance` double DEFAULT NULL,
  `cancel` varchar(45) CHARACTER SET latin1 COLLATE latin1_swedish_ci DEFAULT NULL,
  `saletype` varchar(45) DEFAULT NULL COMMENT '????????????',
  `paid` varchar(45) DEFAULT NULL,
  `vattype` varchar(45) DEFAULT NULL,
  `vattotal` double DEFAULT NULL,
  `billing` varchar(5) DEFAULT 'false',
  `credit_day` double DEFAULT NULL,
  `ref_doc` varchar(45) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `IndexBillDate` (`billdate`) USING BTREE,
  KEY `IndexBillID` (`bill_id`) USING BTREE,
  KEY `IndexCustName` (`cust_name`),
  KEY `Index_5` (`cancel`),
