CREATE TABLE `stockcard` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `product_id` int(11) DEFAULT NULL,
  `bill_id` varchar(45) DEFAULT NULL,
  `product_unit_level` int(10) unsigned DEFAULT NULL,
  `LOCATION_STORE` int(11) DEFAULT NULL,
  `TRANS_DATE` datetime DEFAULT NULL,
  `TRANS_TYPE` varchar(45) DEFAULT NULL,
  `TRANS_ITEM` double DEFAULT NULL,
  `TRANS_BALANCE` double DEFAULT NULL,
  `TRANS_ALL_BALANCE` double DEFAULT NULL,
  `TRANS_ALL_LOC_BALANCE` double DEFAULT NULL,
  `PREV_BALANCE` double DEFAULT NULL,
  `PREV_ALL_BALANCE` double DEFAULT NULL,
  `PREV_ALL_LOC_BALANCE` double DEFAULT NULL,
  `puser` varchar(256) DEFAULT NULL,
  `product_unit_name` varchar(45) DEFAULT NULL,
  `warehouse_code` varchar(40) NOT NULL,
  `location_code` varchar(60) NOT NULL,
  `shelf_code` varchar(60) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_stockcard_bill_id` (`bill_id`),
  KEY `idx_stockcard_product_id` (`product_id`),
  KEY `idx_stockcard_TRANS_DATE` (`TRANS_DATE`),
  KEY `idx_stockcard_slot` (`warehouse_code`,`location_code`,`shelf_code`)
) ENGINE=InnoDB AUTO_INCREMENT=430 DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci;
